import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import API from './api'; 
import './App.css';

const Login = () => {
  const [formData, setFormData] = useState({
    email: '',
    password: '',
  });
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const response = await API.post('/auth/login', formData);

      if (response.data.success) {
        localStorage.setItem('token', response.data.token);
        localStorage.setItem('user', JSON.stringify(response.data.user));
        
        alert('Login successful! Welcome ' + response.data.user.name);
        navigate('/'); 
      }
    } catch (error) {
      console.error('Login error details:', error.response?.data);
      alert(error.response?.data?.message || 'Login failed. Please check your credentials.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h2 style={styles.title}>Citizen Login</h2>
        <form onSubmit={handleSubmit}>
          <div style={styles.formGroup}>
            <label style={styles.label}>Email Address</label>
            <input
              type="email"
              name="email"
              style={styles.input}
              value={formData.email}
              onChange={handleChange}
              required
              placeholder="enter your email"
            />
          </div>
          <div style={styles.formGroup}>
            <label style={styles.label}>Password</label>
            <input
              type="password"
              name="password"
              style={styles.input}
              value={formData.password}
              onChange={handleChange}
              required
              placeholder="enter your password"
            />
          </div>
          <button type="submit" style={styles.button} disabled={loading}>
            {loading ? 'Logging in...' : 'Login'}
          </button>
        </form>
        
        <p style={styles.note}>
          Don't have an account? <Link to="/register" style={styles.link}>Sign Up here</Link>
        </p>
      </div>
    </div>
  );
};

// Restoring your original CSS styles
const styles = {
  container: {
    height: "100vh",
    backgroundColor: "#3a3a50",
    color: "#f0f0f0",
    display: "flex",
    flexDirection: "column",
    justifyContent: "center",
    alignItems: "center",
    fontFamily: "Arial, sans-serif",
  },
  card: {
    background: "rgba(255,255,255,0.1)",
    padding: "40px",
    borderRadius: "15px",
    boxShadow: "0 10px 30px rgba(0,0,0,0.5)",
    width: "350px"
  },
  title: { 
    fontSize: "2rem", 
    marginBottom: "20px",
    textAlign: "center"
  },
  formGroup: {
    marginBottom: "15px",
    textAlign: "left"
  },
  label: {
    display: "block",
    marginBottom: "5px",
    fontSize: "14px"
  },
  input: {
    padding: "12px",
    width: "100%",
    borderRadius: "5px",
    border: "none",
    fontSize: "14px",
    boxSizing: "border-box"
  },
  button: {
    width: "100%",
    padding: "12px",
    backgroundColor: "#6c63ff",
    color: "white",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer",
    fontSize: "16px",
    fontWeight: "bold",
    marginTop: "10px"
  },
  note: {
    marginTop: "20px",
    textAlign: "center",
    fontSize: "14px",
    color: "#ccc"
  },
  link: {
    color: "#6c63ff",
    textDecoration: "none",
    fontWeight: "bold"
  }
};

export default Login;
